import React from 'react';
import { DEFAULT_EMPTY_VALUE } from '@spotter/app-client-toolkit';
import { Popover, PopoverProps, Tooltip } from 'antd';
import { SptComponentProvider } from '../Provider';
import './style/index.less';

export interface SptPopoverListProps extends PopoverProps {
    /**
     * 列表数据
     */
    list?: string[];
    /**
     * 渲染函数，list有多个值的时候，不会对第一个执行
     */
    renderItem?: (arg: string) => React.ReactNode;
}

const PopoverListBase: React.FC<SptPopoverListProps> = ({
    list,
    placement = 'right',
    trigger = 'hover',
    renderItem,
    ...props
}) => {
    return (
        <div className="popover-list-container" id="popover-list-container">
            {list && list?.length > 0 ? (
                list?.length > 1 ? (
                    <Popover
                        placement={placement}
                        content={list?.map((b: string, index: number) => (
                            <div className="popover-list-item" key={index}>
                                {renderItem ? renderItem(b) : b}
                            </div>
                        ))}
                        trigger={trigger}
                        overlayClassName="popover-list-overlay"
                        {...props}
                    >
                        <div className="popover-list-text">
                            <span>{list?.[0]}</span>
                            {/* <Tooltip title={`共${list?.length ?? 0}个`}>
                                <div className="popover-list-tab-num">+{(list?.length ?? 0) - 1}</div>
                            </Tooltip> */}
                            <div className="popover-list-tab-num">+{(list?.length ?? 0) - 1}</div>
                        </div>
                    </Popover>
                ) : renderItem ? (
                    renderItem(list[0])
                ) : (
                    list[0]
                )
            ) : (
                DEFAULT_EMPTY_VALUE
            )}
        </div>
    );
};

/**
 * 额外数据气泡展示
 * @param props
 * @returns
 */
const SptPopoverList: React.FC<SptPopoverListProps> = (props) => {
    return (
        <SptComponentProvider>
            <PopoverListBase {...props} />
        </SptComponentProvider>
    );
};

export default SptPopoverList;
